// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{})
}

type ChiServerOptions struct {
	BaseURL          string
	BaseRouter       chi.Router
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, r chi.Router) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseRouter: r,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, r chi.Router, baseURL string) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseURL:    baseURL,
		BaseRouter: r,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options ChiServerOptions) http.Handler {
	r := options.BaseRouter

	if r == nil {
		r = chi.NewRouter()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}
	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/services/haproxy/configuration/frontends/{parent_name}/binds", wrapper.GetAllBindFrontend)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/services/haproxy/configuration/frontends/{parent_name}/binds", wrapper.CreateBindFrontend)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/services/haproxy/configuration/frontends/{parent_name}/binds/{name}", wrapper.DeleteBindFrontend)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/services/haproxy/configuration/frontends/{parent_name}/binds/{name}", wrapper.GetBindFrontend)
	})
	r.Group(func(r chi.Router) {
		r.Put(options.BaseURL+"/services/haproxy/configuration/frontends/{parent_name}/binds/{name}", wrapper.ReplaceBindFrontend)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/services/haproxy/configuration/log_forwards/{parent_name}/binds", wrapper.GetAllBindLogForward)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/services/haproxy/configuration/log_forwards/{parent_name}/binds", wrapper.CreateBindLogForward)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/services/haproxy/configuration/log_forwards/{parent_name}/binds/{name}", wrapper.DeleteBindLogForward)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/services/haproxy/configuration/log_forwards/{parent_name}/binds/{name}", wrapper.GetBindLogForward)
	})
	r.Group(func(r chi.Router) {
		r.Put(options.BaseURL+"/services/haproxy/configuration/log_forwards/{parent_name}/binds/{name}", wrapper.ReplaceBindLogForward)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/services/haproxy/configuration/peers/{parent_name}/binds", wrapper.GetAllBindPeer)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/services/haproxy/configuration/peers/{parent_name}/binds", wrapper.CreateBindPeer)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/services/haproxy/configuration/peers/{parent_name}/binds/{name}", wrapper.DeleteBindPeer)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/services/haproxy/configuration/peers/{parent_name}/binds/{name}", wrapper.GetBindPeer)
	})
	r.Group(func(r chi.Router) {
		r.Put(options.BaseURL+"/services/haproxy/configuration/peers/{parent_name}/binds/{name}", wrapper.ReplaceBindPeer)
	})

	return r
}

